import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('GuildScene')
export class GuildScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    createGuildBtn: Button = null;
    
    @property(Button)
    joinGuildBtn: Button = null;
    
    @property(Node)
    myGuildPanel: Node = null;
    
    @property(Node)
    guildListPanel: Node = null;
    
    @property(Label)
    guildNameLabel: Label = null;
    
    @property(Label)
    guildLevelLabel: Label = null;
    
    @property(Label)
    memberCountLabel: Label = null;
    
    @property(ScrollView)
    memberListScrollView: ScrollView = null;
    
    @property(Node)
    memberItemPrefab: Node = null;
    
    private hasGuild: boolean = false;
    private guildData = {
        name: '财神殿',
        level: 5,
        members: 45,
        maxMembers: 50,
        notice: '欢迎加入财神殿，一起发财！'
    };
    
    private members = [
        { id: 1, name: '帮主', level: 50, role: 'leader', contribution: 9999 },
        { id: 2, name: '长老1', level: 45, role: 'elder', contribution: 5000 },
        { id: 3, name: '长老2', level: 42, role: 'elder', contribution: 4500 },
        { id: 4, name: '成员1', level: 30, role: 'member', contribution: 1000 },
        { id: 5, name: '成员2', level: 25, role: 'member', contribution: 500 }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.createGuildBtn.node.on(Button.EventType.CLICK, this.onCreateGuild, this);
        this.joinGuildBtn.node.on(Button.EventType.CLICK, this.onJoinGuild, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        if (this.hasGuild) {
            this.myGuildPanel.active = true;
            this.guildListPanel.active = false;
            
            this.guildNameLabel.string = this.guildData.name;
            this.guildLevelLabel.string = `等级: ${this.guildData.level}`;
            this.memberCountLabel.string = `成员: ${this.guildData.members}/${this.guildData.maxMembers}`;
            
            this.updateMemberList();
        } else {
            this.myGuildPanel.active = false;
            this.guildListPanel.active = true;
        }
    }
    
    updateMemberList() {
        const content = this.memberListScrollView.content;
        content.removeAllChildren();
        
        for (const member of this.members) {
            const item = instantiate(this.memberItemPrefab);
            
            item.getChildByName('NameLabel').getComponent(Label).string = member.name;
            item.getChildByName('LevelLabel').getComponent(Label).string = `Lv.${member.level}`;
            item.getChildByName('RoleLabel').getComponent(Label).string = 
                member.role === 'leader' ? '帮主' : member.role === 'elder' ? '长老' : '成员';
            item.getChildByName('ContribLabel').getComponent(Label).string = `贡献: ${member.contribution}`;
            
            content.addChild(item);
        }
    }
    
    onCreateGuild() {
        const name = prompt('请输入门派名称:');
        if (name) {
            this.hasGuild = true;
            this.guildData.name = name;
            this.updateUI();
        }
    }
    
    onJoinGuild() {
        // 显示门派列表，选择加入
        console.log('显示可加入的门派列表');
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
